### 3. POLICY AND INTENT BACKEND MODELS

**Intent Schema (SurrealDB):**

**Migration 0021** - `/Users/marcus/conductor/workspaces/brain-v1/quebec/schema/migrations/0021_intent_node.surql`

```surql
DEFINE TABLE OVERWRITE intent SCHEMAFULL;

-- Core fields
DEFINE FIELD goal ON intent TYPE string;
DEFINE FIELD reasoning ON intent TYPE string;
DEFINE FIELD status ON intent TYPE string
  ASSERT $value IN ["draft", "pending_auth", "pending_veto", "authorized", "executing", "completed", "vetoed", "failed"];
DEFINE FIELD priority ON intent TYPE int ASSERT $value >= 0 AND $value <= 100;

-- Action specification
DEFINE FIELD action_spec ON intent TYPE object;
DEFINE FIELD action_spec.provider ON intent TYPE string;
DEFINE FIELD action_spec.action ON intent TYPE string;
DEFINE FIELD action_spec.params ON intent TYPE option<object>;

-- Budget constraint
DEFINE FIELD budget_limit ON intent TYPE option<object>;
DEFINE FIELD budget_limit.amount ON intent TYPE float;
DEFINE FIELD budget_limit.currency ON intent TYPE string;

-- Evaluation result (populated by authorizer)
DEFINE FIELD evaluation ON intent TYPE option<object>;
DEFINE FIELD evaluation.decision ON intent TYPE string ASSERT $value IN ["APPROVE", "REJECT"];
DEFINE FIELD evaluation.risk_score ON intent TYPE int ASSERT $value >= 0 AND $value <= 100;
DEFINE FIELD evaluation.reason ON intent TYPE string;
DEFINE FIELD evaluation.evaluated_at ON intent TYPE datetime;
DEFINE FIELD evaluation.policy_only ON intent TYPE bool;
DEFINE FIELD evaluation.policy_trace ON intent TYPE option<array<object>>;

-- Veto window
DEFINE FIELD veto_expires_at ON intent TYPE option<datetime>;
DEFINE FIELD veto_reason ON intent TYPE option<string>;

-- Error tracking
DEFINE FIELD error_reason ON intent TYPE option<string>;

-- Traceability
DEFINE FIELD trace_id ON intent TYPE string;
DEFINE FIELD requester ON intent TYPE record<identity>;
DEFINE FIELD workspace ON intent TYPE record<workspace>;
DEFINE FIELD created_at ON intent TYPE datetime;
DEFINE FIELD updated_at ON intent TYPE option<datetime>;
DEFINE FIELD expiry ON intent TYPE option<datetime>;

-- Indexes
DEFINE INDEX OVERWRITE intent_workspace_status ON intent FIELDS workspace, status;
DEFINE INDEX OVERWRITE intent_created_at ON intent FIELDS created_at;
DEFINE INDEX OVERWRITE intent_trace_id ON intent FIELDS trace_id;
DEFINE INDEX OVERWRITE intent_veto_expires ON intent FIELDS veto_expires_at;

-- Relations
DEFINE TABLE OVERWRITE triggered_by TYPE RELATION IN intent OUT task SCHEMAFULL;
DEFINE TABLE OVERWRITE gates TYPE RELATION IN intent OUT agent_session SCHEMAFULL;
DEFINE TABLE OVERWRITE vetoed_by TYPE RELATION IN identity OUT intent SCHEMAFULL;
DEFINE FIELD reason ON vetoed_by TYPE string;
DEFINE FIELD vetoed_at ON vetoed_by TYPE datetime;

-- Event: fire on transition TO pending_auth
DEFINE EVENT OVERWRITE intent_pending_auth ON intent
  ASYNC RETRY 3
  WHEN $before.status != "pending_auth" AND $after.status = "pending_auth"
  THEN { http::post("http://127.0.0.1:{PORT}/api/intents/" + <string> meta::id($after.id) + "/evaluate", $after, ...); };
```

**Intent TypeScript Types:**

**types.ts** - `/Users/marcus/conductor/workspaces/brain-v1/quebec/app/src/server/intent/types.ts`

```typescript
export type IntentStatus = 
  | "draft" | "pending_auth" | "pending_veto" | "authorized" 
  | "executing" | "completed" | "vetoed" | "failed";

export type ActionSpec = {
  provider: string;
  action: string;
  params?: Record<string, unknown>;
};

export type BudgetLimit = {
  amount: number;
  currency: string;
};

export type EvaluationResult = {
  decision: "APPROVE" | "REJECT";
  risk_score: number;
  reason: string;
};

export type RoutingDecision =
  | { route: "auto_approve" }
  | { route: "veto_window"; expires_at: Date }
  | { route: "reject"; reason: string };

export type IntentRecord = {
  id: RecordId<"intent", string>;
  goal: string;
  reasoning: string;
  status: IntentStatus;
  priority: number;
  action_spec: ActionSpec;
  budget_limit?: BudgetLimit;
  evaluation?: EvaluationResult & {
    evaluated_at: Date;
    policy_only: boolean;
    policy_trace?: PolicyTraceEntry[];
    human_veto_required?: boolean;
  };
  veto_expires_at?: Date;
  veto_reason?: string;
  error_reason?: string;
  authorization_details?: BrainAction[];
  dpop_jwk_thumbprint?: string;
  token_issued_at?: Date;
  token_expires_at?: Date;
  trace_id: RecordId<"trace", string>;
  requester: RecordId<"identity", string>;
  workspace: RecordId<"workspace", string>;
  created_at: Date;
  updated_at?: Date;
  expiry?: Date;
};
```

**Intent State Machine:**

**status-machine.ts** - Defines state transitions and validation

**Intent Queries:**

**intent-queries.ts** - `/Users/marcus/conductor/workspaces/brain-v1/quebec/app/src/server/intent/intent-queries.ts`

Core functions:
- `createIntent(surreal, params): Promise<RecordId<"intent">>`
- `updateIntentStatus(surreal, intentRecord, targetStatus, updateFields): Promise<void>`
- `listPendingIntents(surreal, workspaceRecord, filters): Promise<IntentRecord[]>`
- `getIntentById(surreal, intentRecord): Promise<IntentRecord>`
- `createTrace(surreal, params): Promise<RecordId<"trace">>`

**Intent Authorization:**

**authorizer.ts** - `/Users/marcus/conductor/workspaces/brain-v1/quebec/app/src/server/intent/authorizer.ts`

```typescript
export type LlmEvaluator = (
  intent: { goal, reasoning, action_spec, budget_limit?, priority? },
  signal?: AbortSignal
) => Promise<EvaluationResult>;

export async function evaluateIntent(input: EvaluateIntentInput): Promise<{
  decision: "APPROVE" | "REJECT";
  risk_score: number;
  reason: string;
  policy_only: boolean;
  policy_trace: PolicyTraceEntry[];
  human_veto_required: boolean;
}>;
```

Pipeline:
1. Policy gate evaluation (using policies from identity + workspace)
2. LLM evaluation (risk assessment)
3. Routing decision (auto-approve, veto window, or reject)

**Intent Routes:**

**intent-routes.ts** - `/Users/marcus/conductor/workspaces/brain-v1/quebec/app/src/server/intent/intent-routes.ts`

- `POST /api/intents/{intentId}/evaluate` - Policy + LLM evaluation
- Creates transition plan based on routing decision
- Updates intent status: authorized, pending_veto, or vetoed
- Logs evaluation events

**Policy Schema (SurrealDB):**

**Migration 0024** - `/Users/marcus/conductor/workspaces/brain-v1/quebec/schema/migrations/0024_policy_node.surql`

```surql
BEGIN TRANSACTION;

DEFINE TABLE OVERWRITE policy SCHEMAFULL;
DEFINE FIELD title ON policy TYPE string;
DEFINE FIELD description ON policy TYPE option<string>;
DEFINE FIELD version ON policy TYPE int ASSERT $value > 0;
DEFINE FIELD status ON policy TYPE string
  ASSERT $value IN ['active', 'draft', 'deprecated', 'testing', 'superseded'];

-- Selector: when to apply policy
DEFINE FIELD selector ON policy TYPE object;
DEFINE FIELD selector.workspace ON policy TYPE option<string>;
DEFINE FIELD selector.agent_role ON policy TYPE option<string>;
DEFINE FIELD selector.resource ON policy TYPE option<string>;

-- Rules: conditions + effects
DEFINE FIELD rules ON policy TYPE array<object>;
DEFINE FIELD rules[*].id ON policy TYPE string;
DEFINE FIELD rules[*].condition ON policy TYPE object | array FLEXIBLE;
DEFINE FIELD rules[*].condition[*].field ON policy TYPE option<string>;
DEFINE FIELD rules[*].condition[*].operator ON policy TYPE option<string>;
DEFINE FIELD rules[*].effect ON policy TYPE string ASSERT $value IN ['allow', 'deny'];
DEFINE FIELD rules[*].priority ON policy TYPE int;

-- Authorization
DEFINE FIELD human_veto_required ON policy TYPE bool DEFAULT false;
DEFINE FIELD max_ttl ON policy TYPE option<string>;

-- Metadata
DEFINE FIELD created_by ON policy TYPE record<identity>;
DEFINE FIELD workspace ON policy TYPE record<workspace>;
DEFINE FIELD supersedes ON policy TYPE option<record<policy>>;
DEFINE FIELD created_at ON policy TYPE datetime;
DEFINE FIELD updated_at ON policy TYPE option<datetime>;

-- Indexes
DEFINE INDEX policy_workspace_status ON policy FIELDS workspace, status;

-- Graph relations
DEFINE TABLE OVERWRITE governing TYPE RELATION IN identity OUT policy SCHEMAFULL;
DEFINE TABLE OVERWRITE protects TYPE RELATION IN policy OUT workspace SCHEMAFULL;

-- Intent.evaluation extends with policy trace
DEFINE FIELD evaluation.policy_trace[*].policy_id ON intent TYPE string;
DEFINE FIELD evaluation.policy_trace[*].policy_version ON intent TYPE int;
DEFINE FIELD evaluation.policy_trace[*].rule_id ON intent TYPE string;
DEFINE FIELD evaluation.policy_trace[*].effect ON intent TYPE string ASSERT $value IN ['allow', 'deny'];
DEFINE FIELD evaluation.policy_trace[*].matched ON intent TYPE bool;
DEFINE FIELD evaluation.policy_trace[*].priority ON intent TYPE int;
DEFINE FIELD evaluation.human_veto_required ON intent TYPE option<bool>;

COMMIT TRANSACTION;
```

**Policy TypeScript Types:**

**types.ts** - `/Users/marcus/conductor/workspaces/brain-v1/quebec/app/src/server/policy/types.ts`

```typescript
export type RulePredicate = {
  field: string;
  operator: "eq" | "neq" | "lt" | "lte" | "gt" | "gte" | "in" | "not_in" | "exists";
  value: string | number | boolean | string[];
};

export type RuleCondition = RulePredicate | RulePredicate[];

export type PolicyRule = {
  id: string;
  condition: RuleCondition;
  effect: "allow" | "deny";
  priority: number;
};

export type PolicySelector = {
  workspace?: string;
  agent_role?: string;
  resource?: string;
};

export type PolicyStatus = "draft" | "testing" | "active" | "deprecated" | "superseded";

export type PolicyRecord = {
  id: RecordId<"policy">;
  title: string;
  description?: string;
  version: number;
  status: PolicyStatus;
  selector: PolicySelector;
  rules: PolicyRule[];
  human_veto_required: boolean;
  max_ttl?: string;
  created_by: RecordId<"identity">;
  workspace: RecordId<"workspace">;
  supersedes?: RecordId<"policy">;
  created_at: Date;
  updated_at?: Date;
};

export type PolicyTraceEntry = {
  policy_id: string;
  policy_version: number;
  rule_id: string;
  effect: "allow" | "deny";
  matched: boolean;
  priority: number;
};

export type PolicyGateResult =
  | {
      passed: true;
      policy_trace: PolicyTraceEntry[];
      human_veto_required: boolean;
      warnings: PolicyGateWarning[];
    }
  | {
      passed: false;
      reason: string;
      policy_trace: PolicyTraceEntry[];
      deny_rule_id: string;
      warnings: PolicyGateWarning[];
    };

export type IntentEvaluationContext = {
  goal: string;
  reasoning: string;
  priority: number;
  action_spec: ActionSpec;
  budget_limit?: BudgetLimit;
  requester_type: string;
  requester_role?: string;
};
```

**Policy Gate Evaluation:**

**policy-gate.ts** - `/Users/marcus/conductor/workspaces/brain-v1/quebec/app/src/server/policy/policy-gate.ts`

```typescript
export async function evaluatePolicyGate(
  surreal: Surreal,
  identityId: RecordId<"identity">,
  workspaceId: RecordId<"workspace">,
  context: IntentEvaluationContext
): Promise<PolicyGateResult>;
```

Pipeline:
1. Load active policies (identity-governing + workspace-protecting)
2. Deduplicate policies by ID
3. Collect and sort rules by priority
4. Evaluate conditions against intent context
5. Track policy trace (which rules matched/failed)
6. Return pass/fail with trace and warnings

**Policy Queries:**

**policy-queries.ts** - `/Users/marcus/conductor/workspaces/brain-v1/quebec/app/src/server/policy/policy-queries.ts`

- `loadActivePolicies(surreal, identityId, workspaceId): Promise<PolicyRecord[]>`
  - Queries: `SELECT ->governing->policy.* AS policies FROM identity`
  - Queries: `SELECT <-protects<-policy.* AS policies FROM workspace`
  - Deduplicates and filters for status='active'

- `createPolicy(surreal, params): Promise<{ policyId, policyRecord }>`

**Predicate Evaluation:**

**predicate-evaluator.ts** - Evaluates individual rule conditions against intent context

