 58→async function resolveProjectName(
 59→  surreal: Surreal,
 60→  entityRecord: RecordId<string, string>,
 61→  ctx: ProjectContext,
 62→  relation: "belongs_to" | "has_feature" = "belongs_to",
 63→): Promise<string | undefined> {
 64→  if (relation === "has_feature") {
 65→    const [projRows] = await surreal
 66→      .query<[Array<RecordId<"project", string>>]>(
 67→        "SELECT VALUE `in` FROM has_feature WHERE out = $entity AND `in` IN $projects LIMIT 1;",
 68→        { entity: entityRecord, projects: ctx.projectRecords },
 69→      )
 70→      .collect<[Array<RecordId<"project", string>>]>();
 71→    return projRows[0] ? ctx.projectNameById.get(toRecordIdString(projRows[0])) : undefined;
 72→  }
 73→
 74→  const [projRows] = await surreal
 75→    .query<[Array<RecordId<"project", string>>]>(
 76→      "SELECT VALUE out FROM belongs_to WHERE `in` = $entity AND out IN $projects LIMIT 1;",
 77→      { entity: entityRecord, projects: ctx.projectRecords },
 78→    )
 79→    .collect<[Array<RecordId<"project", string>>]>();
 80→  return projRows[0] ? ctx.projectNameById.get(toRecordIdString(projRows[0])) : undefined;
 81→}
