834→export async function listPendingVetoIntents(
835→  input: WorkspaceQueryInput,
836→): Promise<PendingIntentRow[]> {
837→  const [rows] = await input.surreal
838→    .query<[
839→      Array<{
840→        id: RecordId<"intent", string>;
841→        goal: string;
842→        status: string;
843→        priority: number;
844→        evaluation?: { risk_score: number; reason: string };
845→        veto_expires_at?: string | Date;
846→        created_at: string | Date;
847→      }>,
848→    ]>(
849→      [
850→        "SELECT id, goal, status, priority, evaluation, veto_expires_at, created_at",
851→        "FROM intent",
852→        "WHERE status = 'pending_veto'",
853→        `AND ${WORKSPACE_SCOPE_CLAUSE}`,
854→        "ORDER BY priority DESC, created_at ASC",
855→        "LIMIT $limit;",
856→      ].join(" "),
857→      { workspace: input.workspaceRecord, limit: input.limit },
858→    )
859→    .collect<[
860→      Array<{
861→        id: RecordId<"intent", string>;
862→        goal: string;
863→        status: string;
864→        priority: number;
865→        evaluation?: { risk_score: number; reason: string };
866→        veto_expires_at?: string | Date;
867→        created_at: string | Date;
868→      }>,
869→    ]>();
870→
871→  return rows.map((row) => ({
872→    id: row.id,
873→    goal: row.goal,
874→    status: row.status,
875→    priority: row.priority,
876→    ...(row.evaluation ? { risk_score: row.evaluation.risk_score, reason: row.evaluation.reason } : {}),
877→    ...(row.veto_expires_at ? { veto_expires_at: row.veto_expires_at } : {}),
