882→export function mapPendingIntentToFeedItem(row: PendingIntentRow): GovernanceFeedItem {
883→  const rawId = row.id.id as string;
884→  const riskLabel = row.risk_score !== undefined ? ` (risk ${row.risk_score})` : "";
885→
886→  return {
887→    id: `intent:${rawId}:pending_veto`,
888→    tier: "blocking",
889→    entityId: `intent:${rawId}`,
890→    entityKind: "intent",
891→    entityName: row.goal,
892→    reason: `Intent awaiting human review${riskLabel}`,
893→    status: row.status,
894→    priority: row.priority > 50 ? "high" : "medium",
895→    createdAt: toIso(row.created_at),
896→    actions: intentActions(),
897→  };
