899→
900→function intentActions(): GovernanceFeedAction[] {
901→  return [
902→    { action: "confirm", label: "Approve" },
903→    { action: "override", label: "Veto" },
904→    { action: "discuss", label: "Discuss" },
905→  ];
906→}
