  1→import { RecordId } from "surrealdb";
  2→import { HttpError } from "../http/errors";
  3→import { logError, logInfo } from "../http/observability";
  4→import { jsonError, jsonResponse } from "../http/response";
  5→import type { ServerDependencies } from "../runtime/types";
  6→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  7→import {
  8→  getProjectGraphView,
  9→  getFocusedGraphView,
 10→  getWorkspaceGraphOverview,
 11→  parseRecordIdString,
 12→  type GraphEntityTable,
 13→} from "./queries";
 14→import { transformToReagraph } from "./transform";
 15→
 16→export function createGraphRouteHandler(
 17→  deps: ServerDependencies,
 18→): (workspaceId: string, url: URL) => Promise<Response> {
 19→  return (workspaceId: string, url: URL) => handleGraphRoute(deps, workspaceId, url);
 20→}
 21→
 22→async function handleGraphRoute(
 23→  deps: ServerDependencies,
 24→  workspaceId: string,
 25→  url: URL,
 26→): Promise<Response> {
 27→  let workspaceRecord: RecordId<"workspace", string>;
 28→  try {
 29→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 30→  } catch (error) {
 31→    if (error instanceof HttpError) {
 32→      return jsonError(error.message, error.status);
 33→    }
 34→    logError("graph.route.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 35→    return jsonError("failed to resolve workspace", 500);
 36→  }
 37→
 38→  const projectParam = url.searchParams.get("project")?.trim();
 39→  const centerParam = url.searchParams.get("center")?.trim();
 40→  const depthParam = url.searchParams.get("depth")?.trim();
 41→  const depth = depthParam ? Math.max(1, Math.min(3, Number(depthParam) || 2)) : 2;
 42→
 43→  try {
 44→    if (centerParam) {
 45→      const entityTables: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "suggestion"];
 46→      const centerRecord = parseRecordIdString(centerParam, entityTables);
 47→      const raw = await getFocusedGraphView({
 48→        surreal: deps.surreal,
 49→        workspaceRecord,
 50→        centerEntityRecord: centerRecord,
 51→        depth,
 52→      });
 53→      const result = transformToReagraph(raw);
 54→      logInfo("graph.route.focused", "Focused graph view served", {
 55→        workspaceId,
 56→        center: centerParam,
 57→        depth,
 58→        nodeCount: result.nodes.length,
 59→        edgeCount: result.edges.length,
 60→      });
 61→      return jsonResponse(result, 200);
 62→    }
 63→
 64→    if (projectParam) {
 65→      const projectRecord = new RecordId("project", projectParam);
 66→      const raw = await getProjectGraphView({
 67→        surreal: deps.surreal,
 68→        workspaceRecord,
 69→        projectRecord,
 70→      });
 71→      const result = transformToReagraph(raw);
 72→      logInfo("graph.route.project", "Project graph view served", {
 73→        workspaceId,
 74→        project: projectParam,
 75→        nodeCount: result.nodes.length,
 76→        edgeCount: result.edges.length,
 77→      });
 78→      return jsonResponse(result, 200);
 79→    }
 80→
 81→    const raw = await getWorkspaceGraphOverview({
 82→      surreal: deps.surreal,
 83→      workspaceRecord,
 84→    });
 85→    const result = transformToReagraph(raw);
 86→    logInfo("graph.route.overview", "Workspace graph overview served", {
 87→      workspaceId,
 88→      nodeCount: result.nodes.length,
 89→      edgeCount: result.edges.length,
 90→    });
 91→    return jsonResponse(result, 200);
 92→  } catch (error) {
 93→    logError("graph.route.failed", "Graph route failed", error, {
 94→      workspaceId,
 95→      project: projectParam,
 96→      center: centerParam,
 97→    });
 98→    const message = error instanceof Error ? error.message : "graph query failed";
 99→    return jsonError(message, 500);
100→  }
101→}
